compliant:
void good_function() {
    FILE *file = fopen("data.txt", "r");
    if (file) {
        // process file
        fclose(file); // Compliant - properly closed
    }
}

void another_good_function() {
    int fd = open("file.txt", O_RDONLY);
    if (fd != -1) {
        // process file
        close(fd); // Compliant - properly closed
    }
}
